export type PaidPlatform = "meta" | "google" | "tiktok";
export type CampaignVerdict = "scale" | "hold" | "watch" | "kill";
export type Tone = "loss" | "amber" | "profit" | "ok";

export interface PlatformGroup {
  id: PaidPlatform;
  name: string;
  /** "2 campaigns · 2 active" */
  meta: string;
  spend: string;
  trueRev: string;
  /** Verified ROAS (e.g. "2.4×") */
  verified: string;
  poas: string;
  poasTone: Tone;
  budgetPct: number;
}

