export interface AttrGauge {
  platform: PaidPlatform;
  real: string;
  claimed: string;
  airPct: number;
  /** Air dollar amount, e.g. "+$37K air". Empty when air ≤ 8%. */
  airAmount: string;
  airTier: "hi" | "mid" | "lo";
}

