export interface Campaign {
  id: string;
  platform: PaidPlatform;
  name: string;
  goal: string;
  /** "$800/day" */
  budget: string;
  /** "14d creative" or "8d Fresh" or "30d Stale" */
  creativeAge: string;
  creativeTone: "fresh" | "stale" | "neutral";
  /** Optional frequency badge, "freq 4.1 ⚠" */
  freq?: string;
  freqWarn?: boolean;
  /** Out-of-stock note. */
  oos?: string;
  spend: string;
  trueRev: string;
  /** "—" for awareness campaigns */
  reported: string;
  verified: string;
  /** "↑28% over" / "✓7% honest" */
  verifiedNote: string;
  verifiedOver: boolean;
  /** "1.2×" or "—" */
  poas: string;
  poasTone: Tone;
  /** 6 normalized 0..100 heights for the mini trend bar. */
  trend: number[];
  verdict: CampaignVerdict;
  /** CSS gradient + photo URL combined for the cr-thumb. */
  thumb: string;
  /** True if the thumb shows a play overlay (video creative). */
  video?: boolean;
  /** Extra sub-line tokens, e.g. "reach 85.2K · CPM $59 · hook 38%". */
  extras?: string[];
}

