import {
  PLATFORM_GROUPS,
  PLATFORM_LABEL,
  ATTR_GAUGES,
  CAMPAIGNS,
  VERDICT_LABEL,
  paidMetrics,
  paidAI,
  ROAS_TREND,
  RETURN_TREND,
  type Campaign,
  type PaidPlatform,
} from "@/features/growth/api/growth-paid-data";
import "./paid.css";

const PERIOD_LABELS = ["This Month", "Last 7 Days", "Last 30 Days"];

