const arrowIcon = (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <line x1="5" y1="12" x2="19" y2="12" />
    <polyline points="12 5 19 12 12 19" />
  </svg>
);

export default function PaidPage() {
  const [periodIdx, setPeriodIdx] = useState(0);
  const { openBridge } = useBridge();

  return (
    <div className="growth-paid-page">
      <DeptHeader
        dept="growth"
        title="Paid Performance"
        meta={
          <>
            <span className="live">Live</span> · Cross-platform advertising with true attribution and profit-adjusted ROAS
          </>
        }
        actions={
          <>
            <button className="btn-util">View Campaigns</button>
            <button
              className="btn-util primary"
              type="button"
              onClick={() => openBridge("growth")}
            >
              Reallocate Budget →
            </button>
          </>
        }
      />
      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} accent="var(--d-growth)" />

      {/* Metric strip — 6 cells */}
      <div className="metric-strip">
        <Metric label="Total Spend" v={paidMetrics.spend} d={paidMetrics.spendDelta} dDir="up" sub={paidMetrics.spendSub} />
        <Metric label="True Revenue" v={paidMetrics.revenue} vTone="green" d={paidMetrics.revenueDelta} dDir="up" sub={paidMetrics.revenueSub} />
        <Metric label="True ROAS" v={paidMetrics.roas} d={paidMetrics.roasDelta} dDir="down" sub={paidMetrics.roasSub} />
        <Metric label="Profit ROAS" v={paidMetrics.poas} vTone="amber" d={paidMetrics.poasDelta} dDir="down" sub={paidMetrics.poasSub} />
        <Metric label="Avg CPA" v={paidMetrics.cpa} d={paidMetrics.cpaDelta} dDir="down" sub={paidMetrics.cpaSub} />
        <Metric label="Campaigns" v={paidMetrics.campaigns} d={paidMetrics.campaignsDelta} dDir="flat" sub={paidMetrics.campaignsSub} />
      </div>

      <AIStrip label={paidAI.label} meta={paidAI.meta} cards={paidAI.cards} />

      {/* Budget by platform */}
      <SectionLabel>Budget by platform</SectionLabel>
      <div className="budget-bar">
        {PLATFORM_GROUPS.map((p) => (
          <div
            key={p.id}
            className={`budget-seg ${p.id}`}
            style={{ width: `${p.budgetPct}%` }}
          >
            {PLATFORM_LABEL[p.id]} {p.budgetPct}%
          </div>
        ))}
      </div>
      <div className="poas-row">
        {PLATFORM_GROUPS.map((p) => (
          <div key={p.id} className={`poas-field ${p.poasTone}`}>
            <div className="pf-head">
              <span className="pf-ic">{PLATFORM_LOGO[p.id]}</span>
              <span className="pf-name">{PLATFORM_LABEL[p.id]}</span>
              <span className="pf-share">{p.budgetPct}% of spend</span>
            </div>
            <div className="pf-val">{p.poas}</div>
            <div className="pf-sub">
              POAS · {p.poasTone === "profit" ? "earns" : "loses"} ${p.poasTone === "profit" ? "0.40" : p.poas === "0.6×" ? "0.40" : "0.20"} per $1
            </div>
          </div>
        ))}
      </div>

      {/* Attribution reality check */}
      <SectionLabel>Attribution reality check</SectionLabel>
      <div className="attr-block">
        <div className="attr-head">
          <svg className="attr-ic" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
            <circle cx="12" cy="12" r="9" />
            <circle cx="12" cy="12" r="4.2" />
            <line x1="12" y1="1.5" x2="12" y2="4.5" />
            <line x1="12" y1="19.5" x2="12" y2="22.5" />
            <line x1="1.5" y1="12" x2="4.5" y2="12" />
            <line x1="19.5" y1="12" x2="22.5" y2="12" />
          </svg>
          <div>
            <div className="attr-head-title">Attribution Reality Check</div>
            <div className="attr-head-sub">
              Platforms over-reported revenue by $44K. The solid bar is what your orders verify — the red gap is air the platform claimed but no order backs.
            </div>
          </div>
          <div className="attr-head-gap">
            <div className="n">27%</div>
            <div className="l">Total air</div>
          </div>
        </div>
        <div className="attr-rows">
          {ATTR_GAUGES.map((g) => (
            <div key={g.platform} className="gauge-row">
              <div className="gauge-top">
                <div className="gauge-plat">
                  {PLATFORM_LOGO[g.platform]}
                  {PLATFORM_LABEL[g.platform]}
                </div>
                <div className="gauge-readout">
                  <span className="gauge-real">{g.real}</span>
                  <span className="gauge-claim">
                    claimed <s>{g.claimed}</s>
                  </span>
                  <span className={`gauge-pct ${g.airTier}`}>{g.airPct}% air</span>
                </div>
              </div>
              <div className="track">
                <div className="track-claimed" style={{ width: "100%" }} />
                <div className="track-air" style={{ left: `${100 - g.airPct}%`, right: 0 }}>
                  {g.airAmount}
                </div>
                <div className={`track-real ${g.platform}`} style={{ width: `${100 - g.airPct}%` }}>
                  <span className="v">{g.real} real</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* All campaigns */}
      <SectionLabel>All campaigns</SectionLabel>
      <div className="search-row">
        <div className="search-box">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
            <circle cx="11" cy="11" r="8" />
            <line x1="21" y1="21" x2="16.65" y2="16.65" />
          </svg>
          <input type="text" placeholder="Search campaigns, platforms, or goals..." />
        </div>
        <span className="search-count">{CAMPAIGNS.length} campaigns · {CAMPAIGNS.length} active</span>
      </div>
      <div className="filter-bar">
        {["All Platforms", "All Statuses", "All Goals", "Spend: High to Low"].map((label) => (
          <button key={label} className="filter-pill" type="button">
            {label}
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <polyline points="6 9 12 15 18 9" />
            </svg>
          </button>
        ))}
      </div>

      <div className="camp-list">
        <div className="camp-cols">
          <span className="c" />
          <span className="c">Campaign</span>
          <span className="c r">Spend</span>
          <span className="c r">True Rev</span>
          <span className="c r">Reported</span>
          <span className="c r">
            <span className="vmark" />
            Verified
          </span>
          <span className="c r">POAS</span>
          <span className="c r">Trend</span>
          <span className="c r">Verdict</span>
        </div>

        {PLATFORM_GROUPS.map((g) => (
          <PlatformGroupBlock
            key={g.id}
            group={g}
            campaigns={CAMPAIGNS.filter((c) => c.platform === g.id)}
            onBridge={() => openBridge("growth")}
          />
        ))}
      </div>

      {/* Trend cards */}
      <SectionLabel>ROAS &amp; spend trends</SectionLabel>
      <div className="trends-grid">
        <div className="trend-card">
          <div className="trend-card-head">
            <span className="trend-card-title">ROAS vs. POAS · 9 weeks</span>
            <div className="trend-now">
              <div className="n">{ROAS_TREND.hero}</div>
              <div className="d down">{ROAS_TREND.heroDelta}</div>
            </div>
          </div>
          <div className="trend-legend">
            <span>
              <span className="sw" style={{ background: "var(--d-growth)" }} />
              True ROAS
            </span>
            <span>
              <span className="sw" style={{ background: "var(--d-finance)" }} />
              Profit ROAS
            </span>
            <span>
              <span className="sw" style={{ background: "var(--ink-3)" }} />
              Target 3.0×
            </span>
          </div>
          <RoasPoasTrend
            data={ROAS_TREND.weeks.map((w, i) => ({
              period: w,
              trueRoas: ROAS_TREND.trueRoas[i],
              poas: ROAS_TREND.poas[i],
            }))}
          />
          <div className="trend-note warn">
            <span className="ic">↓</span>
            <span>{ROAS_TREND.note}</span>
          </div>
        </div>

        <div className="trend-card">
          <div className="trend-card-head">
            <span className="trend-card-title">Return per $1 spent · 9 weeks</span>
            <div className="trend-now">
              <div className="n warn">{RETURN_TREND.hero}</div>
              <div className="d down">{RETURN_TREND.heroDelta}</div>
            </div>
          </div>
          <div className="trend-legend">
            <span>Each bar = dollars returned per dollar spent that week</span>
          </div>
          <ReturnPerDollar
            data={RETURN_TREND.weeks.map((w, i) => ({
              period: w,
              value: RETURN_TREND.perDollar[i],
            }))}
          />
          <div className="trend-note amber">
            <span className="ic">⚠</span>
            <span>{RETURN_TREND.note}</span>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ──────────────────────────────────────────── */

function Metric({
  label,
  v,
  d,
  dDir,
  sub,
  vTone,
}: {
  label: string;
  v: string;
  d: string;
  dDir: "up" | "down" | "flat";
  sub: string;
  vTone?: "green" | "amber" | "red";
}) {
  return (
    <div className="metric">
      <div className="metric-l">{label}</div>
      <div className={`metric-v${vTone ? " " + vTone : ""}`}>{v}</div>
      <div className={`metric-d ${dDir}`}>{d}</div>
      <div className="metric-s">{sub}</div>
    </div>
  );
}

function PlatformGroupBlock({
  group,
  campaigns,
  onBridge,
}: {
  group: typeof PLATFORM_GROUPS[number];
  campaigns: Campaign[];
  onBridge: () => void;
}) {
  return (
    <>
      <div className={`platform-group-head ${group.id}`}>
        <div className="pg-id">
          <span className="pg-icon">{PLATFORM_LOGO[group.id]}</span>
          <span className="pg-name">{group.name}</span>
          <span className="pg-meta">{group.meta}</span>
        </div>
        <div className="pg-tot">{group.spend}</div>
        <div className="pg-tot up">{group.trueRev}</div>
        <div className="pg-tot span2">{group.verified}</div>
        <div className={`pg-tot poas ${group.poasTone}`}>{group.poas}</div>
      </div>
      {campaigns.map((c) => (
        <CampaignRow key={c.id} c={c} onBridge={onBridge} />
      ))}
    </>
  );
}

function CampaignRow({ c, onBridge }: { c: Campaign; onBridge: () => void }) {
  return (
    <div className={`camp-row v-${c.verdict}`}>
      <div className="cr-thumb" style={{ background: c.thumb }}>
        {c.video && (
          <div className="play">
            <svg viewBox="0 0 16 16">
              <path d="M4 3 L13 8 L4 13 Z" />
            </svg>
          </div>
        )}
      </div>
      <div className="cr-name-wrap">
        <div className="cr-name">{c.name}</div>
        <div className="cr-sub">
          <span className="tag goal">{c.goal}</span>
          <span>{c.budget}</span>
          {c.creativeTone === "fresh" && <span className="tag fresh">{c.creativeAge}</span>}
          {c.creativeTone === "stale" && <span className="tag stale">{c.creativeAge}</span>}
          {c.creativeTone === "neutral" && <span>{c.creativeAge}</span>}
          {c.freq && (
            <span className={`freq${c.freqWarn ? " warn" : ""}`}>{c.freq}</span>
          )}
          {c.oos && <span className="oos">{c.oos}</span>}
          {c.extras?.map((x) => <span key={x}>{x}</span>)}
        </div>
      </div>
      <div className="cr-col">
        <div className="cr-val">{c.spend}</div>
      </div>
      <div className="cr-col">
        <div className={`cr-val${c.trueRev === "—" ? " muted" : ""}`}>{c.trueRev}</div>
      </div>
      <div className="cr-reported">{c.reported}</div>
      <div className={`cr-verified ${c.verifiedOver ? "over" : "ok"}`}>
        <span className="vn">{c.verified}</span>
        <span className="vg">{c.verifiedNote}</span>
      </div>
      <div className={`cr-poas ${c.poasTone}`}>{c.poas}</div>
      <div className="cr-col">
        <div className="cr-trend">
          {c.trend.map((h, i) => (
            <span key={i} className="bar" style={{ height: `${h}%` }} />
          ))}
        </div>
      </div>
      <div className="cr-action">
        <span className="cr-verdict">
          <span className="vdot" />
          {VERDICT_LABEL[c.verdict]}
        </span>
      </div>
      <button className="cr-bridge" type="button" onClick={onBridge}>
        {arrowIcon}
        Bridge
      </button>
    </div>
  );
}
