"use client";

/* ════════════════════════════════════════════════════════════════════════
   <ReturnPerDollar> — Tier-2 fading-bars chart per CHART-STANDARD §5.1.

   Question it answers: is each ad dollar working less over time?
   Bars fade from full opacity → ~0.45 across the weeks so the diminishing
   returns are *visually* what you read first. Breakeven floor at $1 marks
   the cliff every bar should stay above.

   §2 compliance: real-px viewBox, typed data, ChartStates, reduced motion.
   ──────────────────────────────────────────────────────────────────────── */

import { useEffect, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export interface ReturnPerDollarPoint {
  period: string;
  /** Dollars returned per $1 spent in that period. */
  value: number;
}

export interface ReturnPerDollarProps {
  data?: ReturnPerDollarPoint[];
  /** Y-axis ceiling. Default derived from data. */
  yMax?: number;
  /** Breakeven dollar reference. Default 1.0. */
  breakeven?: number;
  state?: ChartState;
  label?: string;
}

export const sampleReturnPerDollarData: ReturnPerDollarPoint[] = [
  { period: "W1", value: 4.1 },
  { period: "W2", value: 3.95 },
  { period: "W3", value: 3.82 },
  { period: "W4", value: 3.66 },
  { period: "W5", value: 3.45 },
  { period: "W6", value: 3.28 },
  { period: "W7", value: 3.12 },
  { period: "W8", value: 2.95 },
  { period: "W9", value: 2.8 },
];

export function ReturnPerDollar({
  data = sampleReturnPerDollarData,
  yMax,
  breakeven = 1.0,
  state = "ready",
  label = "Return per dollar",
}: ReturnPerDollarProps) {
  const { ref, width } = useChartSize({ min: 360, fallback: 560 });
  const reduce = usePrefersReducedMotion();
  const [drawn, setDrawn] = useState(false);

  const W = Math.max(360, width);
  const H = 240;
  const padT = 30;
  const padB = 44;
  const padL = 30;
  const padR = 14;
  const plotT = padT;
  const plotB = H - padB;
  const plotL = padL;
  const plotR = W - padR;
  const n = data.length;
  const max = yMax ?? Math.max(5, Math.ceil(Math.max(...data.map((d) => d.value))));

  const X = (i: number) => plotL + ((i + 0.5) / n) * (plotR - plotL);
  const Y = (v: number) => plotB - (v / max) * (plotB - plotT);
  const barW = ((plotR - plotL) / n) * 0.62;

  useEffect(() => {
    if (reduce) {
      setDrawn(true);
      return;
    }
    const r = requestAnimationFrame(() => requestAnimationFrame(() => setDrawn(true)));
    return () => cancelAnimationFrame(r);
  }, [reduce]);

  return (
    <div ref={ref}>
      <ChartStates state={state} height={H} label={label}>
        <svg className="returnpd-svg tchart" viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", height: H, display: "block" }}>
          {[1, 2, 3, 4].filter((v) => v < max).map((v) => (
            <g key={`g-${v}`}>
              <line className="grid" x1={plotL} y1={Y(v)} x2={plotR} y2={Y(v)} />
              <text className="tc-ylab" x={plotL - 4} y={Y(v) - 5} textAnchor="end">
                ${v}
              </text>
            </g>
          ))}
          <line className="tc-ref be" x1={plotL} y1={Y(breakeven)} x2={plotR} y2={Y(breakeven)} />
          <text className="tc-reflab be" x={plotR} y={Y(breakeven) - 5} textAnchor="end">
            Breakeven ${breakeven.toFixed(0)}
          </text>
          <line className="base" x1={plotL} y1={plotB} x2={plotR} y2={plotB} />

          {data.map((d, i) => {
            const x = X(i) - barW / 2;
            const y = Y(d.value);
            const h = plotB - y;
            const dollarsBelowOne = d.value < breakeven;
            const fading = i / Math.max(1, n - 1); // 0 → 1
            const opacity = 0.45 + 0.55 * (1 - fading);
            // Grow-in: bars rise from baseline once drawn flips true
            return (
              <rect
                key={i}
                x={x}
                y={drawn ? y : plotB}
                width={barW}
                height={drawn ? h : 0}
                rx={2}
                fill={dollarsBelowOne ? "var(--loss)" : "#1D9E75"}
                opacity={drawn ? opacity : 0}
                style={{
                  transition: `y 0.7s cubic-bezier(.4,.1,.2,1) ${i * 0.06}s, height 0.7s cubic-bezier(.4,.1,.2,1) ${i * 0.06}s, opacity 0.5s ${i * 0.06}s`,
                }}
              />
            );
          })}

          {data.map((d, i) => (
            <text
              key={d.period}
              className="xlab"
              x={X(i)}
              y={plotB + 22}
              textAnchor="middle"
            >
              {d.period}
            </text>
          ))}
        </svg>
      </ChartStates>
    </div>
  );
}
