"use client";

/* ════════════════════════════════════════════════════════════════════════
   <RoasPoasTrend> — Tier-2 dual-line trend per CHART-STANDARD §5.1.

   Question it answers: is each ad dollar working as hard as it was?
   Two lines (True ROAS + Profit ROAS) over N weeks against a target
   reference (3.0×) and a breakeven floor (1.0×). The lines draw in
   left→right on mount so the slide toward breakeven feels earned.

   §2 compliance: real-px viewBox, typed data, ChartStates, reduced motion.
   ──────────────────────────────────────────────────────────────────────── */

import { useEffect, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export interface RoasPoasPoint {
  /** Period label, e.g. "W1". */
  period: string;
  /** Verified ROAS (×). */
  trueRoas: number;
  /** Profit ROAS — after product cost (×). */
  poas: number;
}

export interface RoasPoasTrendProps {
  data?: RoasPoasPoint[];
  /** ROAS target reference line. Default 3.0×. */
  target?: number;
  /** Breakeven reference line. Default 1.0×. */
  breakeven?: number;
  /** Lower bound of the y-scale. Default 0.5. */
  yMin?: number;
  /** Upper bound of the y-scale. Default derived from data. */
  yMax?: number;
  state?: ChartState;
  label?: string;
}

export const sampleRoasPoasData: RoasPoasPoint[] = [
  { period: "W1", trueRoas: 4.1, poas: 2.4 },
  { period: "W2", trueRoas: 4.05, poas: 2.32 },
  { period: "W3", trueRoas: 3.95, poas: 2.18 },
  { period: "W4", trueRoas: 3.85, poas: 2.05 },
  { period: "W5", trueRoas: 3.78, poas: 1.94 },
  { period: "W6", trueRoas: 3.66, poas: 1.82 },
  { period: "W7", trueRoas: 3.54, poas: 1.7 },
  { period: "W8", trueRoas: 3.46, poas: 1.6 },
  { period: "W9", trueRoas: 3.4, poas: 1.5 },
];

export function RoasPoasTrend({
  data = sampleRoasPoasData,
  target = 3.0,
  breakeven = 1.0,
  yMin = 0.5,
  yMax,
  state = "ready",
  label = "ROAS vs POAS",
}: RoasPoasTrendProps) {
  const { ref, width } = useChartSize({ min: 360, fallback: 560 });
  const reduce = usePrefersReducedMotion();
  const [drawn, setDrawn] = useState(false);

  const W = Math.max(360, width);
  const H = 240;
  const padT = 30;
  const padB = 44;
  const padL = 10;
  const padR = 14;
  const plotT = padT;
  const plotB = H - padB;
  const plotL = padL;
  const plotR = W - padR;
  const n = data.length;
  const max = yMax ?? Math.max(target + 1, Math.ceil(Math.max(...data.map((d) => d.trueRoas))) + 0.6);

  const X = (i: number) => plotL + (i / Math.max(1, n - 1)) * (plotR - plotL);
  const Y = (v: number) => plotB - ((v - yMin) / (max - yMin)) * (plotB - plotT);

  const trueRoasPath = data.map((d, i) => `${X(i).toFixed(1)},${Y(d.trueRoas).toFixed(1)}`).join(" ");
  const poasPath = data.map((d, i) => `${X(i).toFixed(1)},${Y(d.poas).toFixed(1)}`).join(" ");

  const lineLen = (plotR - plotL) + 80;

  useEffect(() => {
    if (reduce) {
      setDrawn(true);
      return;
    }
    const r = requestAnimationFrame(() => requestAnimationFrame(() => setDrawn(true)));
    return () => cancelAnimationFrame(r);
  }, [reduce]);

  return (
    <div ref={ref}>
      <ChartStates state={state} height={H} label={label}>
        <svg className="roaspoas-svg tchart" viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", height: H, display: "block" }}>
          {[1, 2, 3, 4].filter((v) => v < max).map((v) => (
            <g key={`g-${v}`}>
              <line className="grid" x1={plotL} y1={Y(v)} x2={plotR} y2={Y(v)} />
              <text className="tc-ylab" x={plotL + 2} y={Y(v) - 5}>
                {v.toFixed(1)}×
              </text>
            </g>
          ))}
          <line className="tc-ref target" x1={plotL} y1={Y(target)} x2={plotR} y2={Y(target)} />
          <text className="tc-reflab" x={plotR} y={Y(target) - 5} textAnchor="end">
            Target {target.toFixed(1)}×
          </text>
          <line className="tc-ref be" x1={plotL} y1={Y(breakeven)} x2={plotR} y2={Y(breakeven)} />
          <text className="tc-reflab be" x={plotR} y={Y(breakeven) - 5} textAnchor="end">
            Breakeven {breakeven.toFixed(1)}×
          </text>
          <line className="base" x1={plotL} y1={plotB} x2={plotR} y2={plotB} />

          {data.map((_, i) => (
            <line key={i} className="tk" x1={X(i)} y1={plotB} x2={X(i)} y2={plotB - 7} opacity={0.3} />
          ))}

          <polyline
            points={trueRoasPath}
            fill="none"
            stroke="#7F77DD"
            strokeWidth={2.4}
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{
              strokeDasharray: lineLen,
              strokeDashoffset: drawn ? 0 : lineLen,
              transition: "stroke-dashoffset 1.4s cubic-bezier(.4,.1,.2,1)",
            }}
          />
          <polyline
            points={poasPath}
            fill="none"
            stroke="#1D9E75"
            strokeWidth={2.4}
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{
              strokeDasharray: lineLen,
              strokeDashoffset: drawn ? 0 : lineLen,
              transition: "stroke-dashoffset 1.4s cubic-bezier(.4,.1,.2,1) 0.15s",
            }}
          />

          {/* End markers (last point) */}
          {n > 0 && (
            <g style={{ opacity: drawn ? 1 : 0, transition: "opacity 0.3s 1.5s" }}>
              <circle
                cx={X(n - 1)}
                cy={Y(data[n - 1].trueRoas)}
                r={4.5}
                fill="#7F77DD"
                stroke="#fff"
                strokeWidth={1.5}
              />
              <circle
                cx={X(n - 1)}
                cy={Y(data[n - 1].poas)}
                r={4.5}
                fill="#1D9E75"
                stroke="#fff"
                strokeWidth={1.5}
              />
            </g>
          )}

          {data.map((d, i) => (
            <text
              key={d.period}
              className="xlab"
              x={X(i)}
              y={plotB + 22}
              textAnchor="middle"
            >
              {d.period}
            </text>
          ))}
        </svg>
      </ChartStates>
    </div>
  );
}
